import json

lines = open('ios_crash.ips').readlines()
raw_body = ''.join(lines[1:])
raw_body = raw_body.replace('\"vmregioninfo\"', '\"vmregioninfo_lower\"')
crash = json.loads(raw_body)

# lastExceptionBacktrace - check structure
leb = crash.get('lastExceptionBacktrace')
if leb:
    print('type:', type(leb))
    if isinstance(leb, list):
        for j, frame in enumerate(leb[:20]):
            idx = frame.get('imageIndex', -1)
            offset = frame.get('imageOffset', 0)
            img = crash['usedImages'][idx] if idx < len(crash['usedImages']) else {}
            addr = img.get('base', 0) + offset
            name = img.get('name', '?')
            print(f'  #{j}: {name} 0x{addr:x} (offset 0x{offset:x})')
    elif isinstance(leb, dict):
        for j, frame in enumerate(leb.get('frames', [])[:20]):
            idx = frame.get('imageIndex', -1)
            offset = frame.get('imageOffset', 0)
            img = crash['usedImages'][idx] if idx < len(crash['usedImages']) else {}
            addr = img.get('base', 0) + offset
            name = img.get('name', '?')
            print(f'  #{j}: {name} 0x{addr:x} (offset 0x{offset:x})')
else:
    print('No lastExceptionBacktrace')
